import { Switch as HeadlessSwitch } from "@headlessui/react";
import PropTypes from "prop-types";
import React from "react";
import cn from "../../helpers/classnames";

const sizes = {
    large: {
        parent: "h-6 w-11",
        inner: "h-5 w-5",
        translate: "translate-x-5",
    },
    medium: {
        parent: "h-5 w-8",
        inner: "h-4 w-4",
        translate: "translate-x-3",
    },
    small: {
        parent: "h-3 w-5",
        inner: "h-2 w-2",
        translate: "translate-x-2",
    },
};

// TODO: Native checkbox input `checked` and `disabled` properties are not prefixed with `is`.
// Decide on the naming convention.
export const Switch = ({ isChecked = false, size = "medium", ...rest }) => {
    return (
        <HeadlessSwitch
            checked={isChecked}
            className={cn(
                "ui-switch",
                isChecked ? "bg-primary disabled:bg-gray-light" : "bg-gray disabled:bg-gray-light",
                "relative inline-flex flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none",
                sizes[size].parent,
            )}
            {...rest}
        >
            <span
                className={cn(
                    isChecked ? sizes[size].translate : "translate-x-0",
                    "ui-switch-inner pointer-events-none inline-block transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out",
                    sizes[size].inner,
                )}
            />
        </HeadlessSwitch>
    );
};

Switch.propTypes = {
    isChecked: PropTypes.bool,
    size: PropTypes.string,
};

Switch.Group = ({ className, children }) => {
    return (
        <HeadlessSwitch.Group as="div" className={cn("ui-switch-group", "inline-flex items-center", className)}>
            {children}
        </HeadlessSwitch.Group>
    );
};

Switch.Group.displayName = "Switch.Group";

Switch.Group.propTypes = {
    className: PropTypes.string,
    children: PropTypes.node.isRequired,
};

Switch.Label = ({ direction = "left", className, children }) => {
    return (
        <HeadlessSwitch.Label
            as="span"
            className={cn("ui-switch-label", "cursor-pointer", direction === "left" ? "mr-2" : "ml-2", className)}
        >
            {children}
        </HeadlessSwitch.Label>
    );
};

Switch.Label.displayName = "Switch.Label";

Switch.Label.propTypes = {
    direction: PropTypes.string,
    className: PropTypes.string,
    children: PropTypes.node.isRequired,
};
